// Summary: Tests Visibility rendering and verifies breakpoint class composition for from/to combinations.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { Visibility } from './Visibility';

describe('Visibility', () => {
  it('renders children into the DOM tree', () => {
    render(
      <Visibility>
        <span>Content</span>
      </Visibility>
    );
    expect(screen.getByText('Content')).toBeInTheDocument();
  });

  it('applies from="lg" tokens', () => {
    render(<Visibility from="lg">From only</Visibility>);
    const className = screen.getByText('From only').className;
    const tokens = ['invisible', 'lg:visible'];
    expect(tokens.every(token => className.includes(token))).toBe(true);
  });

  it('applies to="xl" tokens', () => {
    render(<Visibility to="xl">To only</Visibility>);
    const className = screen.getByText('To only').className;
    const tokens = ['visible', 'xl:invisible'];
    expect(tokens.every(token => className.includes(token))).toBe(true);
  });

  it('applies between range tokens for from="md" to="xl"', () => {
    render(
      <Visibility from="md" to="xl">
        Between
      </Visibility>
    );
    const className = screen.getByText('Between').className;
    const tokens = ['invisible', 'md:visible', 'xl:invisible'];
    expect(tokens.every(token => className.includes(token))).toBe(true);
  });

  it('applies outside range tokens for from="xl" to="md"', () => {
    render(
      <Visibility from="xl" to="md">
        Outside
      </Visibility>
    );
    const className = screen.getByText('Outside').className;
    const tokens = ['visible', 'md:invisible', 'xl:visible'];
    expect(tokens.every(token => className.includes(token))).toBe(true);
  });

  it('keeps content hidden at exact breakpoint when from="md" to="md"', () => {
    render(
      <Visibility from="md" to="md">
        Same
      </Visibility>
    );
    const className = screen.getByText('Same').className;
    const tokens = ['invisible', 'md:visible', 'md:invisible'];
    expect(tokens.every(token => className.includes(token))).toBe(true);
  });

  it('merges a custom className with composed tokens', () => {
    render(<Visibility className="bg-red-500">Merged</Visibility>);
    const el = screen.getByText('Merged');
    expect(el.className.includes('bg-red-500')).toBe(true);
  });
});
